package 'Comment Example' {
  comment /* This is comment, part of the model,annotating (by default) it's owning package. */
  comment Comment1  /* This is a named comment. */
  comment about Automobile /* This is an unnamed comment, annotating an explicitly specified element.
  */
  part def Automobile;
  alias Car for Automobile {
    comment /* This is a comment annotating its owning element.  */
  }
    comment /* This is a note. It is in the text, but not part of the model.*/
  alias Torque for ISQ::TorqueValue;
}

package 'Package Example' {
  public import ISQ::TorqueValue;
  private import ScalarValues::*;
  part def Automobile;
  alias Car for Automobile;
  alias Torque for ISQ::TorqueValue;
}
